import SwiftUI
import CoreGraphics

// Real MLBAM ballpark contours (GeomMLBStadiums), reduced + stored as compact strings and
// parsed once at runtime. Shared coordinate space: home plate ~ (125, 201); the outfield
// extends toward smaller y. Renderer normalises against MLBBounds so every park sits on one
// scale (true relative sizes). Generated by gen_swift.py — do not hand-edit.

struct RawPark { let abbr: String; let park: String; let jersey: String; let hp: String; let wall: String; let infield: String; let foul: String }

struct Ballpark {
    let abbr: String, park: String, jersey: Color, text: Color
    let homePlate: CGPoint
    let wall: [CGPoint], infield: [CGPoint], foul: [CGPoint]
}

// Global bounds used for the shared transform (with a little pad).
enum MLBBounds { static let minX: CGFloat = 20, maxX: CGFloat = 232, minY: CGFloat = 12, maxY: CGFloat = 238
    static var w: CGFloat { maxX - minX }; static var h: CGFloat { maxY - minY } }

private func pts(_ s: String) -> [CGPoint] {
    s.split(separator: " ").compactMap { pair in
        let xy = pair.split(separator: ","); guard xy.count == 2, let x = Double(xy[0]), let y = Double(xy[1]) else { return nil }
        return CGPoint(x: x, y: y)
    }
}

