private func lumLight(_ hex: String) -> Bool {
    let h = hex.replacingOccurrences(of: "#", with: "")
    guard h.count == 6, let v = Int(h, radix: 16) else { return false }
    let r = Double((v >> 16) & 0xff), g = Double((v >> 8) & 0xff), b = Double(v & 0xff)
    return (0.299 * r + 0.587 * g + 0.114 * b) > 150
}

enum MLBParks {
    static let all: [String: Ballpark] = MLB_RAW.mapValues { r in
        Ballpark(abbr: r.abbr, park: r.park, jersey: Color(hex: r.jersey),
                 text: lumLight(r.jersey) ? Color(hex: "#10131A") : .white,
                 homePlate: pts(r.hp).first ?? CGPoint(x: 125, y: 201),
                 wall: pts(r.wall), infield: pts(r.infield), foul: pts(r.foul))
    }
    /// Match a team name (nickname or city) from a matchup string to its park.
    static func park(forTeam name: String) -> Ballpark? {
        let n = name.lowercased().trimmingCharacters(in: .whitespaces)
        if let k = MLB_ALIAS[n], let p = all[k] { return p }
        for (alias, key) in MLB_ALIAS where n.contains(alias) { if let p = all[key] { return p } }
        return nil
    }
}
